#pragma once
#define BATTERIES_BIT_OPS_UPPER_BOUND_INDEX_OF_HPP

#include <batteries/config.hpp>
//
#include <batteries/int_types.hpp>
#include <batteries/utility.hpp>

#include <hwy/highway.h>

#include <array>
#include <type_traits>

namespace batt {

template <typename T, usize kSize, typename = std::enable_if_t<(kSize <= HWY_LANES(T))>>
inline i32 upper_bound_index_of(T item, const std::array<T, kSize>& vec)
{
    namespace hn = hwy::HWY_NAMESPACE;
    using D = hn::FixedTag<T, kSize>;

    static_assert(MaxLanes(D{}) == kSize);

    const hn::Vec<D> pattern = hn::Set(D{}, item);
    const hn::Vec<D> items = hn::LoadU(D{}, vec.data());
    const hn::Mask<D> mask = hn::Lt(pattern, items);

    return FindFirstTrue(D{}, mask) & 0x7fffffff;
}

template <typename T, usize kSize>
inline i32 slow_upper_bound_index_of(T item, const std::array<T, kSize>& vec)
{
    i32 result = 0;

    for (T v : vec) {
        if (v <= item) {
            ++result;
            continue;
        }
        return result;
    }

    return 0x7fffffff;
}

// TODO [tastolfi 2026-01-21] - Come up with a better optimization strategy.
//
template <typename T, usize kSize, typename = std::enable_if_t<(kSize > HWY_LANES(T))>, typename = void>
inline i32 upper_bound_index_of(T item, const std::array<T, kSize>& vec)
{
    return slow_upper_bound_index_of(item, vec);
}

}  // namespace batt
